-- Ejecutar en Supabase SQL Editor

CREATE TABLE IF NOT EXISTS productos_oportunidades (
  id TEXT PRIMARY KEY,
  nombre TEXT NOT NULL,
  lote TEXT,
  fecha_venc DATE NOT NULL,
  stock INTEGER NOT NULL,
  precio_publico NUMERIC(12,2) NOT NULL,
  precio_outlet NUMERIC(12,2) NOT NULL,
  es_urgente BOOLEAN DEFAULT false,
  imagen_url TEXT,
  activo BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- RLS: tabla pública para lectura
ALTER TABLE productos_oportunidades ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read" ON productos_oportunidades FOR SELECT USING (true);
CREATE POLICY "service_all" ON productos_oportunidades FOR ALL USING (auth.role() = 'service_role');

